#include <vector>
#include <string>
#include <queue>
#include <sstream>
using namespace std;
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {
    }
}
;
class Solution {
    public:
    string serializeAndDeserializeBinaryTree(TreeNode* root) {
        if (!root) return "#";
        stringstream ss;
        queue<TreeNode*> q;
        q.push(root);
        while (!q.empty()) {
            TreeNode* node = q.front();
            q.pop();
            if (node) {
                ss << node->val << ",";
                q.push(node->left);
                q.push(node->right);
            }
            else {
                ss << "#,";
            }
        }
        string serialized = ss.str();
        return serialized.substr(0, serialized.size() - 1); // Remove the last comma
    }
    TreeNode* deserialize(const string& data) {
        if (data == "#") return nullptr;
        stringstream ss(data);
        string item;
        getline(ss, item, ',');
        TreeNode* root = new TreeNode(stoi(item));
        queue<TreeNode*> q;
        q.push(root);
        while (getline(ss, item, ',')) {
            TreeNode* parent = q.front();
            q.pop();
            if (item != "#") {
                parent->left = new TreeNode(stoi(item));
                q.push(parent->left);
            }
            if (!getline(ss, item, ',')) break;
            if (item != "#") {
                parent->right = new TreeNode(stoi(item));
                q.push(parent->right);
            }
        }
        return root;
    }
}
