package main

import (
    "bytes"
    "fmt"
    "strings"
)

type TreeNode struct {
    Val   int
    Left  *TreeNode
    Right *TreeNode
}

func serializeAndDeserializeBinaryTree(root *TreeNode) string {
    if root == nil {
        return ""
    }

    var buffer bytes.Buffer
    queue := []*TreeNode{root}

    for len(queue) > 0 {
        node := queue[0]
        queue = queue[1:]
        if node != nil {
            buffer.WriteString(fmt.Sprintf("%d,", node.Val))
            queue = append(queue, node.Left, node.Right)
        } else {
            buffer.WriteString("nil,")
        }
    }

    return strings.TrimSuffix(buffer.String(), ",")
}

func deserialize(data string) *TreeNode {
    if data == "" {
        return nil
    }

    nodes := strings.Split(data, ",")
    root := &TreeNode{Val: parseValue(nodes[0])}
    queue := []*TreeNode{root}

    for i := 1; i < len(nodes); i++ {
        node := queue[0]
        queue = queue[1:]

        if nodes[i] != "nil" {
            node.Left = &TreeNode{Val: parseValue(nodes[i])}
            queue = append(queue, node.Left)
        }
        i++
        if i < len(nodes) && nodes[i] != "nil" {
            node.Right = &TreeNode{Val: parseValue(nodes[i])}
            queue = append(queue, node.Right)
        }
    }

    return root
}

func parseValue(s string) int {
    var val int
    fmt.Sscanf(s, "%d", &val)
    return val
}

