package main

import (
    "bytes"
    "encoding/json"
    "fmt"
    "strings"
)

type TreeNode struct {
    Val   int
    Left  *TreeNode
    Right *TreeNode
}

func serializeAndDeserializeBinaryTree(root *TreeNode) string {
    if root == nil {
        return "[]"
    }

    var queue []*TreeNode
    queue = append(queue, root)
    var result []interface{}

    for len(queue) > 0 {
        node := queue[0]
        queue = queue[1:]

        if node != nil {
            result = append(result, node.Val)
            queue = append(queue, node.Left, node.Right)
        } else {
            result = append(result, nil)
        }
    }

    // Remove trailing nils for compactness
    for len(result) > 0 && result[len(result)-1] == nil {
        result = result[:len(result)-1]
    }

    data, _ := json.Marshal(result)
    return string(data)
}

func main() {
    // Example usage
    root := &TreeNode{Val: 1, Left: &TreeNode{Val: 2}, Right: &TreeNode{Val: 3}}
    serialized := serializeAndDeserializeBinaryTree(root)
    fmt.Println(serialized)
}

